  coaching_execution = '{"movement_description":"Hold kettlebell or dumbbell at chest, brace trunk, squat to controlled depth with knees tracking toes, and stand without losing posture.","setup":["Select kettlebell or dumbbell load appropriate to skill.","Feet shoulder-width, toes slightly out.","Elbows down, weight close to chest.","Confirm pain-free range and supervision for youth."],"execution_steps":["Brace trunk and set neutral spine.","Sit hips down and back together.","Keep knees tracking over mid-foot.","Reach controlled depth without butt wink or collapse.","Drive through full foot to stand.","Rest fully before the next set."],"breathing_cues":["Big breath and brace at the top — exhale through the sticking point if needed without losing brace."],"coach_cues":["Elbows down.","Ribs down.","Knees out.","Full foot pressure.","Control the descent."],"athlete_cues":["Brace.","Sit down.","Push the floor.","Stand tall."],"common_faults":["Weight drifting away from chest.","Heels rising early.","Knees collapsing inward.","Excessive forward lean or lumbar flexion at bottom.","Rushing reps with short rest.","Using weight beyond clean rep capacity."],"stop_signs":["Knee pain during squat.","Sharp hip or groin pain.","Cannot maintain knee alignment.","Loss of trunk control at depth.","Dizziness or breath-holding with valsalva at inappropriate load."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Box Squat","Air Squat — Skill pattern","Glute Bridge","Mini-Band Hip Activation"],"pairs_well_after":["Front Squat — DB / KB / Barbell","Split Squat","Romanian Deadlift","Farmer Carry"],"good_for_sessions":["capacity_lower_body","squat_capacity","strength_development"],"avoid_before":["Max velocity sprints in same session if heavy squat block precedes Output","Front squat if goblet depth is poor"],"avoid_after":[],"do_not_use_when":["Knee pain with loaded squat","Cannot control knee valgus","Using as conditioning circuit","Youth max load without supervision"]}'::jsonb,
