  coaching_execution = '{"movement_description":"Sit back to box under control, maintain brace at pause, stand without momentum or trunk collapse.","setup":["Set stable box or bench at appropriate height.","Feet shoulder-width, shins relatively vertical at bottom.","Optional goblet or barbell load for progressed athletes.","Confirm box will not slide."],"execution_steps":["Brace and initiate hips back.","Lower under control until light box contact.","Pause without relaxing trunk or collapsing.","Drive through mid-foot to stand.","Finish tall without rocking forward.","Rest fully between sets."],"breathing_cues":["Brace before descent — maintain pressure through the pause."],"coach_cues":["Hips back first.","Light touch.","Stay tight on the box.","Stand without rock.","Knees track toes."],"athlete_cues":["Back.","Touch.","Tight.","Stand."],"common_faults":["Plopping onto the box.","Rocking forward to stand.","Knees shooting forward excessively.","Losing brace at pause.","Box height too low for current mobility.","Short rest turning it into conditioning."],"stop_signs":["Low back pain at bottom or stand.","Knee pain with load.","Cannot stand without momentum.","Box instability.","Athlete fearfully collapses onto box."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["90/90 Hip Mobility","Glute Bridge","Air Squat — Skill pattern"],"pairs_well_after":["Goblet Squat","Split Squat","Front Squat — DB / KB / Barbell"],"good_for_sessions":["capacity_lower_body","squat_capacity","strength_development"],"avoid_before":["Full-depth goblet if athlete cannot control box pause","Heavy frontal-plane work same day if groin sensitive"],"avoid_after":[],"do_not_use_when":["Unstable box","Low back pain with loaded flexion","Athlete plops every rep","Used as plyometric bounce drill"]}'::jsonb,
