-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and physiological qualities for athletic development.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('goblet-squat', 'The goblet squat places load anteriorly, which encourages an upright torso, active bracing, and controlled knee tracking. It builds bilateral knee and hip extension strength that supports jumping, landing, sprinting, and cutting without requiring a barbell rack.', 'Belongs in squat_strength (411) — foundational Capacity bilateral squat before front-loaded barbell work or high-demand unilateral patterns.', 'Primary entry in squat_strength after Output; before front squat, heavy split work, or frontal-plane loading when bilateral squat mechanics are still developing.', 'Capacity builds strength reserve with intentional load, controlled reps, full rest — not Output speed work or Fitness circuits. Do not use as a high-rep conditioning drill, max-youth load without supervision, or substitute when athlete cannot control depth and knee alignment.', 'Regress to box squat or bodyweight squat; progress load, tempo pause, or front squat only when depth and valgus control stay clean. Hypermobility athletes need active foot tripod and knee control — no passive collapse.'),
  ('box-squat', 'The box provides an external depth reference that reduces fear of falling backward and helps athletes learn posterior weight shift. It is useful for teaching consistent ROM, reducing excessive knee travel, and building strength at a controlled range before full-depth squat progressions.', 'Belongs in squat_regression (412) — depth-controlled Capacity squat before full ROM goblet or front squat loading.', 'squat_regression slot for beginners, depth-limited athletes, or return-to-load when full ROM squat quality is inconsistent; before progressing goblet or front squat depth.', 'Capacity builds strength reserve with intentional load, controlled reps, full rest — not Output speed work or Fitness circuits. Do not plop onto the box, bounce off it, or use high-rep touch-and-go as Fitness work.', 'Raise box height or use bodyweight first; lower box and add load only when pause and stand stay controlled. Athletes with hip pinching may need higher box or wider stance.'),
  ('front-squat-db-kb-barbell', 'Front loading increases demand on trunk extensors and upright posture while biasing knee extensor contribution. It builds force capacity in a position relevant to receiving, bracing, and athletic landing patterns when progressed appropriately from goblet squat.', 'Belongs in front_loaded_squat (413) — advanced bilateral Capacity squat after goblet competency.', 'front_loaded_squat after goblet squat competency; before max unilateral loading when athlete needs upright trunk strength for sport and lifting.', 'Capacity builds strength reserve with intentional load, controlled reps, full rest — not Output speed work or Fitness circuits. Do not prescribe barbell front squat before goblet control, use collapsed rack position, or chase load with forward elbow drop.', 'Regress to goblet squat or double KB front squat; progress to barbell only when rack, wrist, and trunk stay organized. Use tempo or pause before load jumps.'),
  ('split-squat', 'Split squats increase unilateral demand on quads and glutes while exposing balance and frontal-plane control deficits that bilateral squats can hide. They build single-leg force capacity relevant to landing, cutting, and lunge patterns in sport.', 'Belongs in split_stance_strength (414) — foundational unilateral Capacity pattern before RFESS.', 'split_stance_strength entry after bilateral goblet or box squat; before RFESS when static split control is established.', 'Capacity builds strength reserve with intentional load, controlled reps, full rest — not Output speed work or Fitness circuits. Do not use short rest walking lunges, allow front knee valgus, or progress to RFESS before static split control is clean.', 'Regress to supported split squat or shorter ROM; add load only when front knee tracks and trunk stays vertical. Complete all reps one side before switching or alternate by set — be consistent.'),
  ('rear-foot-elevated-split-squat', 'Elevating the rear foot increases hip flexion demand and range on the front leg, making RFESS one of the highest unilateral knee-dominant strength tools when progressed from split squat. It builds single-leg force and stability for sport deceleration and landing.', 'Belongs in split_stance_strength (414) — advanced unilateral Capacity after split squat competency.', 'split_stance_strength after split squat competency; high-value unilateral strength before heavy frontal-plane or sled loading.', 'Capacity builds strength reserve with intentional load, controlled reps, full rest — not Output speed work or Fitness circuits. Do not prescribe before split squat control, use unstable bench, or chase load with rear-foot cramping and trunk collapse.', 'Regress to split squat or lower bench height; use counterbalance or support until front knee and trunk stay organized. Reduce load if hip flexor cramping dominates.'),
  ('reverse-lunge', 'Reverse lunges emphasize controlled eccentric loading on the front leg while stepping back reduces some anterior knee stress compared with forward lunging. They build deceleration and single-leg strength relevant to sport change-of-direction and landing.', 'Belongs in lunge_strength (415) — loaded reverse lunge for Capacity decel and single-leg force.', 'lunge_strength after split squat or goblet squat; useful when athletes need lunge strength with less anterior knee shear than forward lunge.', 'Capacity builds strength reserve with intentional load, controlled reps, full rest — not Output speed work or Fitness circuits. Do not use high-rep alternating walking lunges with short rest, allow front knee valgus, or progress load before step-back control is clean.', 'Regress to split squat or supported reverse step; add load when front knee tracks and trunk stays tall. In-place reps per side reduce balance demand vs walking lunges.'),
  ('step-up', 'Step-ups isolate concentric single-leg hip and knee extension while allowing box height to scale demand. They build force capacity for climbing, jumping takeoff, and single-leg stability with less deep eccentric stress than RFESS when programmed appropriately.', 'Belongs in step_up_strength (416) — single-leg concentric Capacity after bilateral and split squat base.', 'step_up_strength after split squat or goblet squat; useful when athletes need vertical single-leg force with reduced eccentric demand vs deep split patterns.', 'Capacity builds strength reserve with intentional load, controlled reps, full rest — not Output speed work or Fitness circuits. Do not push off the back foot, use box too high, or rep out quickly with short rest as a Fitness finisher.', 'Lower box height or use bodyweight; add load only when drive leg does all the work. Step down slowly to control eccentric if knee tolerance allows.'),
  ('lateral-lunge-loaded', 'Loaded lateral lunges train the hip complex in the frontal plane — adductors, abductors, and glutes — which supports lateral deceleration, cutting, and landing. Progressive loading with full rest builds tissue capacity without the speed demand of Output COD work.', 'Belongs in frontal_plane_strength (417) — loaded lateral lunge before Cossack and advanced groin loading.', 'frontal_plane_strength entry before loaded Cossack; after bilateral squat base when athlete needs lateral force capacity for cutting and field sport.', 'Capacity builds strength reserve with intentional load, controlled reps, full rest — not Output speed work or Fitness circuits. Do not load heavily with groin pain, use before bilateral squat base, or rep out lateral lunges before agility with short rest.', 'Regress to bodyweight lateral step or shorter step width; add load only when groin is pain-free and knee tracks. Stay in controlled ROM before deep Cossack progressions.'),
  ('loaded-cossack-squat', 'The loaded Cossack squat combines deep frontal-plane hip mobility with strength through a wide lateral shift. It builds adductor and hip complex capacity for lateral sport demands when progressed from lateral lunge or bodyweight Cossack skill.', 'Belongs in frontal_plane_strength (417) — advanced groin-loading Capacity after lateral lunge or Cossack shift skill.', 'frontal_plane_strength after lateral lunge loaded or Cossack shift skill; highest groin demand in this cluster — conservative loading.', 'Capacity builds strength reserve with intentional load, controlled reps, full rest — not Output speed work or Fitness circuits. Do not load before lateral lunge tolerance, bounce at bottom, or use as dynamic stretch before Output COD when groin is unprepared.', 'Regress to bodyweight Cossack shift or lateral lunge; add load only with pain-free ROM on both sides. Reduce depth before reducing load if groin symptoms appear.'),
  ('heavy-sled-push-sled-drive-march', 'Heavy sled pushing builds concentric knee and hip extension force with minimal eccentric landing stress when performed as slow drive marches. It develops horizontal force capacity and trunk bracing relevant to sport contact, acceleration, and lower-body strength reserve.', 'Belongs in loaded_drive_strength (418) — heavy slow sled Capacity; distinct from light fast sled Output acceleration work.', 'loaded_drive_strength after goblet squat and split squat base; end of squat cluster or paired with carries — heavy slow is Capacity, light fast is Output.', 'Capacity builds strength reserve with intentional load, controlled reps, full rest — not Output speed work or Fitness circuits. Do not use light fast sled sprints here, collapse trunk posture, or program before squat base. Short rest turns heavy push into Fitness.', 'Regress load or distance; use march instead of push when posture breaks. Progress load only when trunk stays braced and knees track. Requires goblet squat and split squat competency.')
) AS v(slug, why_works, why_here, best_placement, misuse, scale_guidance)
JOIN coaching.exercise e ON e.slug = v.slug
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_works = EXCLUDED.why_it_works,
  why_it_goes_here = EXCLUDED.why_it_goes_here,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  scaling_guidance = EXCLUDED.scaling_guidance,
  updated_at = now();

-- Squat / knee-dominant Capacity cluster validation education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_matters, programming_guidance, common_misuse
)
VALUES (
  'validation_rule',
  'capacity_squat_readiness',
  NULL,
  'Squat / Knee-Dominant Capacity without stealing Output quality',
  'Capacity squat patterns need intentional load, controlled reps, and full rest — not warm-up fluff or conditioning circuits.',
  'First Capacity cluster: goblet squat, box squat, front squat, split squat, RFESS, reverse lunge, step-up, lateral lunge, Cossack, and heavy sled drive.',
  'Lower-body force capacity supports jumping, sprinting, landing, cutting, and tumbling. Poor placement, youth overload, or frontal-plane groin stress raises injury risk and reduces Output quality.',
  'Place after Output unless strength-priority; master goblet/box before front squat and RFESS; regress on valgus, groin pain, or sled posture collapse; heavy slow sled is Capacity, light fast sled is Output.',
  'Do not program high-rep squat circuits before Output, max youth loads without supervision, RFESS before split squat, or groin-loading frontal work with pain — regress dose or change phase intent.'
)
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_matters = EXCLUDED.why_it_matters,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  updated_at = now();
